class Solution:
    def findSubstringInWraproundString(self, s: str) -> int:
        dp = [0] * 26
        for i, ch in enumerate(s):
            if i and (ord(ch) - ord(s[i-1]) + 26) % 26 == 1:
                dp[ord(ch)-97] = dp[ord(s[i-1])-97] + 1
            else:
                dp[ord(ch)-97] = 1
        return sum(dp)

