class Solution {
public:
    int findSubstringInWraproundString(string s) {
        int dp[26]={};
        for(int i=0;i<(int)s.size();i++){
            if(i&&(s[i]-s[i-1]+26)%26==1) dp[s[i]-'a']=dp[s[i-1]-'a']+1;
            else dp[s[i]-'a']=1;
        }
        return accumulate(dp,dp+26,0);
    }
};

