int findSubstringInWraproundString(char* s) {
    int dp[26]={0}, ans=0;
    for(int i=0;s[i];i++){
        if(i&&(s[i]-s[i-1]+26)%26==1) dp[s[i]-'a']=dp[s[i-1]-'a']+1;
        else dp[s[i]-'a']=1;
    }
    for(int i=0;i<26;i++) ans+=dp[i];
    return ans;
}
